import { getUrlParams } from '../utils/urlParams.js';
import { primaryDomObject, secDomObject } from '../assets/domObjects.js';

export function obtainDomValues(values) {
  const objValues = {};
  for (const prop in values) {

    objValues[prop] = values[prop].value;

  }

  return objValues;
}

export function clear(obj) {
  for (const prop in obj) {
    obj[prop].value = "";
  }
}

export function handleViewMore(resultado, porcentajes, primaryDomObject) {

  if (resultado.value) {

    alert
      (`Tasa Efectiva Anual: ${porcentajes.tasasEfectivas.tea} %\nTasa Efectiva Total x ${primaryDomObject.ciclos.value} ciclos de ${primaryDomObject.plazo.value} días: ${porcentajes.tasasEfectivas.tet} %\nRendimiento Ajustado: ${porcentajes.rendimientoInversion} %`)

  } else {
    alert('Debes hacer un cálculo primero')
  }
}

export function render(element, value) {
  element.value = value;
}

export function completeFromUrlParams() {

  const params = getUrlParams();

  if (params.tna) {
    primaryDomObject.tna.value = params.tna;

  }

  if (params.montoInicial) {
    primaryDomObject.montoInicial.value = params.montoInicial;

  }

  if (params.plazo) {
    primaryDomObject.plazo.value = params.plazo;
  }

  if (params.ciclos) {
    primaryDomObject.ciclos.value = params.ciclos;
  }

  if (params.adicional) {
    primaryDomObject.adicional.value = params.adicional;
  }

  if (params.inflacion) {

    secDomObject.advanceOptions.checked = true;
    secDomObject.advanceOptions.dispatchEvent(new Event('change'));
    primaryDomObject.inflacion.value = params.inflacion;
  }


  if (params.tna && params.plazo && params.ciclos && params.montoInicial) {
    const manualCalculate = new Event('click');
    secDomObject.calculate.dispatchEvent(manualCalculate);
  }
}